export const InputStates: Story = {
  name: 'Input States',
  render: () => {
    function BackFields({ state }: { state: 'editable' | 'disabled' | 'readonly' }) {
      const inputProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '1838 0008 7261 2332' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '1838 0008 7261 2332' }
            : {};
      const expiryProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '11/27' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '11/27' }
            : {};
      const cvvProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '8177' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '8177' }
            : {};

      return (
        <CreditCard.Back>
          <CreditCard.MagStripe />
          <CreditCard.BackContent>
            <CreditCard.Fieldset aria-label="Card details">
              <CreditCard.Field>
                <CreditCard.FieldLabel>Card number</CreditCard.FieldLabel>
                <CreditCard.Number {...inputProps} />
              </CreditCard.Field>
              <CreditCard.FieldGroup>
                <CreditCard.Field>
                  <CreditCard.FieldLabel>Exp</CreditCard.FieldLabel>
                  <CreditCard.Expiry {...expiryProps} />
                </CreditCard.Field>
                <CreditCard.Field>
                  <CreditCard.FieldLabel>CVV</CreditCard.FieldLabel>
                  <CreditCard.CVV {...cvvProps} />
                </CreditCard.Field>
              </CreditCard.FieldGroup>
            </CreditCard.Fieldset>
          </CreditCard.BackContent>
        </CreditCard.Back>
      );
    }

    return (
      <div style={{ display: 'flex', gap: 24, alignItems: 'start' }}>
        <div style={{ textAlign: 'center' }}>
          <CreditCard.Root defaultFace="back">
            <CreditCard.Content>
              <CardFront />
              <BackFields state="editable" />
            </CreditCard.Content>
          </CreditCard.Root>
          <p style={{ marginTop: 8, fontSize: 13, color: 'var(--gray-9)' }}>Editable</p>
        </div>
        <div style={{ textAlign: 'center' }}>
          <CreditCard.Root defaultFace="back">
            <CreditCard.Content>
              <CardFront />
              <BackFields state="disabled" />
            </CreditCard.Content>
          </CreditCard.Root>
          <p style={{ marginTop: 8, fontSize: 13, color: 'var(--gray-9)' }}>Disabled</p>
        </div>
        <div style={{ textAlign: 'center' }}>
          <CreditCard.Root defaultFace="back">
            <CreditCard.Content>
              <CardFront />
              <BackFields state="readonly" />
            </CreditCard.Content>
          </CreditCard.Root>
          <p style={{ marginTop: 8, fontSize: 13, color: 'var(--gray-9)' }}>Read-only</p>
        </div>
      </div>
    );
  },
};

export const FormIntegration: Story = {
  name: 'Form Integration',
  render: function FormIntegrationStory() {
    const [loading, setLoading] = useState(false);
    const [submitted, setSubmitted] = useState(false);

    return (
      <div style={{ width: 360 }}>
        <Form
          onSubmit={async (e) => {
            e.preventDefault();
            setLoading(true);
            await new Promise((r) => setTimeout(r, 800));
            setSubmitted(true);
            setLoading(false);
          }}
        >
          <CreditCard.Root defaultFace="back">
            <CreditCard.Content>
              <CardFront />
              <CreditCard.Back>
                <CreditCard.MagStripe />
                <CreditCard.BackContent>
                  <CreditCard.Fieldset aria-label="Card details">
                    <CreditCard.Field name="cardNumber">
                      <CreditCard.FieldLabel>Card number</CreditCard.FieldLabel>
                      <CreditCard.Number required />
                      <CreditCard.FieldError match="valueMissing">Card number is required</CreditCard.FieldError>
                      <CreditCard.FieldError match="patternMismatch">Enter a valid card number</CreditCard.FieldError>
                    </CreditCard.Field>
                    <CreditCard.FieldGroup>
                      <CreditCard.Field name="expiry">
                        <CreditCard.FieldLabel>Exp</CreditCard.FieldLabel>
                        <CreditCard.Expiry required pattern="\d{2}/\d{2}" />
                        <CreditCard.FieldError match="valueMissing">Expiration date is required</CreditCard.FieldError>
                        <CreditCard.FieldError match="patternMismatch">
                          Enter a valid expiration date (MM/YY)
                        </CreditCard.FieldError>
                      </CreditCard.Field>
                      <CreditCard.Field name="cvv">
                        <CreditCard.FieldLabel>CVV</CreditCard.FieldLabel>
                        <CreditCard.CVV required />
                        <CreditCard.FieldError match="valueMissing">CVV is required</CreditCard.FieldError>
                      </CreditCard.Field>
                    </CreditCard.FieldGroup>
                  </CreditCard.Fieldset>
                </CreditCard.BackContent>
              </CreditCard.Back>
            </CreditCard.Content>
            <CreditCard.Errors style={{ padding: 16 }} />
          </CreditCard.Root>

          <div style={{ marginTop: 16 }}>
            <Button type="submit" loading={loading} size="3" variant="solid" style={{ width: '100%' }}>
              Save card
            </Button>
          </div>
        </Form>

        {submitted && (
          <Callout.Root color="success" size="1" style={{ marginTop: 12 }}>
            <Callout.Text>Card saved successfully!</Callout.Text>
          </Callout.Root>
        )}

        <Text size="1" color="gray" style={{ display: 'block', marginTop: 12 }}>
          Submit with empty fields to see validation errors.
        </Text>
      </div>
    );
  },
};

export const Colors: Story = {
  name: 'Colors',
  render: function ColorsStory() {
    type InputState = 'default' | 'disabled' | 'readonly';
    const [inputState, setInputState] = useState<InputState>('default');
    const colors = ['lemon', 'blue', 'purple', 'crimson', 'teal', 'orange'] as const;

    function ColoredBack({ state }: { state: InputState }) {
      const numberProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '1838 0008 7261 2332' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '1838 0008 7261 2332' }
            : {};
      const expiryProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '11/27' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '11/27' }
            : { defaultValue: '11/27' };
      const cvvProps =
        state === 'readonly'
          ? { readOnly: true, defaultValue: '8177' }
          : state === 'disabled'
            ? { disabled: true, defaultValue: '8177' }
            : { defaultValue: '8177' };

      return (
        <CreditCard.Back>
          <CreditCard.MagStripe />
          <CreditCard.BackContent>
            <CreditCard.Fieldset aria-label="Card details">
              <CreditCard.Field>
                <CreditCard.FieldLabel>Card number</CreditCard.FieldLabel>
                <CreditCard.Number {...numberProps} />
              </CreditCard.Field>
              <CreditCard.FieldGroup>
                <CreditCard.Field>
                  <CreditCard.FieldLabel>Exp</CreditCard.FieldLabel>
                  <CreditCard.Expiry {...expiryProps} />
                </CreditCard.Field>
                <CreditCard.Field>
                  <CreditCard.FieldLabel>CVV</CreditCard.FieldLabel>
                  <CreditCard.CVV {...cvvProps} />
                </CreditCard.Field>
              </CreditCard.FieldGroup>
            </CreditCard.Fieldset>
          </CreditCard.BackContent>
        </CreditCard.Back>
      );
    }

    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 32, alignItems: 'center' }}>
        <SegmentedControlRadioGroup.Root value={inputState} onValueChange={(v) => setInputState(v as InputState)}>
          <SegmentedControlRadioGroup.Item value="default">Default</SegmentedControlRadioGroup.Item>
          <SegmentedControlRadioGroup.Item value="disabled">Disabled</SegmentedControlRadioGroup.Item>
          <SegmentedControlRadioGroup.Item value="readonly">Read-only</SegmentedControlRadioGroup.Item>
        </SegmentedControlRadioGroup.Root>

        <div style={{ display: 'flex', flexDirection: 'column', gap: 32 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
            <CreditCard.Root defaultFace="front">
              <CreditCard.Content>
                <CardFront />
                <ColoredBack state={inputState} />
              </CreditCard.Content>
            </CreditCard.Root>
            <CreditCard.Root defaultFace="back">
              <CreditCard.Content>
                <CardFront />
                <ColoredBack state={inputState} />
              </CreditCard.Content>
            </CreditCard.Root>
            <Text size="2" color="gray" weight="medium" style={{ minWidth: 60 }}>default</Text>
          </div>
          {colors.map((color) => (
            <div key={color} style={{ display: 'flex', alignItems: 'center', gap: 24 }}>
              <CreditCard.Root color={color} defaultFace="front">
                <CreditCard.Content>
                  <CardFront />
                  <ColoredBack state={inputState} />
                </CreditCard.Content>
              </CreditCard.Root>
              <CreditCard.Root color={color} defaultFace="back">
                <CreditCard.Content>
                  <CardFront />
                  <ColoredBack state={inputState} />
                </CreditCard.Content>
              </CreditCard.Root>
              <Text size="2" color="gray" weight="medium" style={{ minWidth: 60 }}>{color}</Text>
            </div>
          ))}
        </div>
      </div>
    );
  },
};

